import{_ as e,o as a,c as r,a3 as o}from"./chunks/framework.Daqi0Atb.js";const s="/assets/04-01.CsN3qc5V.jpg",n="/assets/04-03.Yr59dmJX.jpg",d="/assets/04-02.LdGr9hHJ.jpg",m=JSON.parse('{"title":"04｜逆向五步法（上）：工业级 Agent 框架源码如何解码","description":"","frontmatter":{},"headers":[],"relativePath":"courses/agent-design/04-逆向五步法（上）：工业级Agent框架源码如何解码.md","filePath":"courses/agent-design/04-逆向五步法（上）：工业级Agent框架源码如何解码.md"}'),i={name:"courses/agent-design/04-逆向五步法（上）：工业级Agent框架源码如何解码.md"};function l(p,t,h,g,c,u){return a(),r("div",null,[...t[0]||(t[0]=[o('<h1 id="_04-逆向五步法-上-工业级-agent-框架源码如何解码" tabindex="-1">04｜逆向五步法（上）：工业级 Agent 框架源码如何解码 <a class="header-anchor" href="#_04-逆向五步法-上-工业级-agent-框架源码如何解码" aria-label="Permalink to &quot;04｜逆向五步法（上）：工业级 Agent 框架源码如何解码&quot;">​</a></h1><p><strong>作者</strong>：黄佳</p><hr><h2 id="一句话脉络" tabindex="-1">一句话脉络 <a class="header-anchor" href="#一句话脉络" aria-label="Permalink to &quot;一句话脉络&quot;">​</a></h2><p>带着&quot;认知功能×执行拓扑&quot;的预期框架去源码里验证——不是信马由缰，是按图索骥。</p><hr><h2 id="逆向工程五步法" tabindex="-1">逆向工程五步法 <a class="header-anchor" href="#逆向工程五步法" aria-label="Permalink to &quot;逆向工程五步法&quot;">​</a></h2><p><img src="'+s+`" alt="逆向五步法总览：Detect → Classify → Filter → Map → Verify"></p><table tabindex="0"><thead><tr><th>步骤</th><th>目标</th></tr></thead><tbody><tr><td>Detect</td><td>找主循环，抓住系统的脊柱</td></tr><tr><td>Classify</td><td>用七脉给组件归类</td></tr><tr><td>Filter</td><td>主动丢掉 70% 噪声</td></tr><tr><td>Map</td><td>落到双轴矩阵</td></tr><tr><td>Verify</td><td>每个判断都要能回到源码</td></tr></tbody></table><hr><h2 id="为什么需要逆向五步法" tabindex="-1">为什么需要逆向五步法 <a class="header-anchor" href="#为什么需要逆向五步法" aria-label="Permalink to &quot;为什么需要逆向五步法&quot;">​</a></h2><p>读 Agent 框架源码容易掉的三个坑：</p><ol><li><strong>README 幻觉</strong> — 知道它&quot;能做什么&quot;，不知道&quot;为什么这样做&quot;、主循环在哪、状态怎么传</li><li><strong>关键词漫游</strong> — grep 出来几百个文件，每个看两眼，脑子里只剩碎片</li><li><strong>从入口一路钻到底</strong> — 70% 代码是配置、日志、类型定义、序列化、UI glue，钻进支路就出不来了</li></ol><p><strong>核心原则：先知道一个 Agent Harness 理论上应该长什么样，再去源码里验证它实际什么样。</strong></p><hr><h2 id="agent-harness-的五个理论地基" tabindex="-1">Agent Harness 的五个理论地基 <a class="header-anchor" href="#agent-harness-的五个理论地基" aria-label="Permalink to &quot;Agent Harness 的五个理论地基&quot;">​</a></h2><p>任何一个工业级 Agent Harness 必然有：</p><ol><li><strong>主循环</strong> — 接收输入→装配上下文→调用模型→处理工具结果→决定下一步</li><li><strong>上下文管理</strong> — 否则 token window 失控，模型不知道该记住什么、丢掉什么</li><li><strong>工具注册和调度</strong> — 行动空间必须有边界</li><li><strong>状态或事件记录</strong> — 长任务可恢复，出问题可回放和审计</li><li><strong>治理边界</strong> — 权限、沙箱、确认、日志、策略</li></ol><hr><h2 id="step-1-detect-—-先找主循环" tabindex="-1">Step 1：Detect — 先找主循环 <a class="header-anchor" href="#step-1-detect-—-先找主循环" aria-label="Permalink to &quot;Step 1：Detect — 先找主循环&quot;">​</a></h2><p>主循环同时碰到三件事：<strong>messages + model call + tool dispatch</strong>。</p><p>搜索关键词：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>rg &quot;tool_call|function_call|tool_use|ToolCall|Action|Observation&quot; .</span></span>
<span class="line"><span>rg &quot;while|loop|step|run|turn|conversation|session&quot; .</span></span>
<span class="line"><span>rg &quot;messages|context|history|state&quot; .</span></span></code></pre></div><p>顺着两个方向交叉定位：</p><ul><li><strong>入口方向</strong>：用户输入、session、conversation、turn</li><li><strong>模型方向</strong>：messages、model、completion、response、tool call</li></ul><p><strong>产出物</strong>：一张不超过 10 个框的粗图。</p><p><img src="`+n+`" alt="Agent Harness 主循环示意图"></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>User Input → Session → Context Builder → LLM → Tool Dispatcher</span></span>
<span class="line"><span>                                              ↑              ↓</span></span>
<span class="line"><span>                                        Event Log ← Observation ← Runtime / Sandbox</span></span></code></pre></div><hr><h2 id="step-2-classify-—-把组件归到七脉" tabindex="-1">Step 2：Classify — 把组件归到七脉 <a class="header-anchor" href="#step-2-classify-—-把组件归到七脉" aria-label="Permalink to &quot;Step 2：Classify — 把组件归到七脉&quot;">​</a></h2><p>找到主循环后，用七脉对号入座。不要只看组件名字，要看它<strong>真正在系统里做什么</strong>。</p><table tabindex="0"><thead><tr><th>组件</th><th>第一判断</th><th>副脉</th></tr></thead><tbody><tr><td>Aider repo map</td><td>Perception（决定哪些代码进入上下文）</td><td>Memory（压缩后的持续认识）</td></tr><tr><td>OpenHands Event System</td><td>Memory（事件账本，可追加可回放）</td><td>Governance（过程可追踪可审计）</td></tr><tr><td>Claude Code Subagent</td><td>Collaboration（任务分给子 Agent）</td><td>Perception（子 Agent 上下文隔离）</td></tr></tbody></table><p>一个组件可以跨多脉。第一遍先找一个主脉，旁边标注副脉即可。</p><hr><h2 id="step-3-filter-—-主动丢掉-70-噪声" tabindex="-1">Step 3：Filter — 主动丢掉 70% 噪声 <a class="header-anchor" href="#step-3-filter-—-主动丢掉-70-噪声" aria-label="Permalink to &quot;Step 3：Filter — 主动丢掉 70% 噪声&quot;">​</a></h2><p><strong>判断标准：这个文件会不会改变 Agent 的决策、上下文、状态、行动或权限？</strong></p><p>如果不是，先标成 boilerplate，暂时放一边。</p><p>第一轮不需要读：</p><ul><li>CLI 参数解析</li><li>UI 布局</li><li>错误文案</li><li>telemetry 上报适配</li><li>schema 类型定义</li><li>provider SDK 包装</li><li>serialization / deserialization</li><li>测试 fixture</li><li>平台兼容性分支</li></ul><p>各框架第一轮过滤建议：</p><table tabindex="0"><thead><tr><th>框架</th><th>优先看</th><th>暂时跳过</th></tr></thead><tbody><tr><td>Claude Code</td><td>工具注册、执行、权限、context 装配</td><td>UI</td></tr><tr><td>Codex CLI</td><td>core、protocol、sandboxing、exec policy</td><td>每个 crate</td></tr><tr><td>Aider</td><td>base_coder.py、repomap.py、repo.py</td><td>prompt variant</td></tr><tr><td>OpenCode</td><td>session、llm agent、permission、lsp</td><td>UI/TUI（只看触发会话和权限）</td></tr><tr><td>OpenClaw</td><td>gateway、channels contract、workspace、memory-host-sdk</td><td>skills 文档</td></tr><tr><td>Hermes Agent</td><td>run_agent.py、hermes_state.py、memory_setup、skills_hub</td><td>每个 CLI 命令</td></tr><tr><td>DeerFlow</td><td>agent router、skill router、memory router、sandbox tests</td><td>集成测试</td></tr><tr><td>OpenHands</td><td>event service、sandbox service、conversation service、runtime README</td><td>前端和集成模板</td></tr></tbody></table><hr><h2 id="step-4-map-—-落到双轴矩阵" tabindex="-1">Step 4：Map — 落到双轴矩阵 <a class="header-anchor" href="#step-4-map-—-落到双轴矩阵" aria-label="Permalink to &quot;Step 4：Map — 落到双轴矩阵&quot;">​</a></h2><p><img src="`+d+'" alt="8 个框架双轴矩阵热力图"></p><p><strong>Map 不能变成贴标签。</strong> 不是写&quot;这是 Memory&quot;，而是逼自己说清楚：</p><ul><li>它解决哪个认知功能？</li><li>采用哪种执行拓扑？</li><li>失败模式是什么？</li></ul><p><strong>实例：OpenHands EventLog</strong></p><p>不是只说&quot;它是 EventLog&quot;，而是说清楚三个工程判断：</p><ol><li>解决 Memory 问题 → 系统状态来自一串事件，不再散落在对象内存里</li><li>也解决 Governance 问题 → 事件可以审计、可以回放</li><li>采用 Chain / append-only 拓扑 → 错误不会被悄悄覆盖，但日志会膨胀，replay 成本需要管理</li></ol><p><strong>产出物</strong>：一张热力图。</p><table tabindex="0"><thead><tr><th>框架</th><th>偏好</th></tr></thead><tbody><tr><td>Aider</td><td>专注代码上下文、编辑和提交</td></tr><tr><td>OpenHands</td><td>重沙箱、事件和运行时</td></tr><tr><td>Hermes</td><td>重记忆、技能和用户模型</td></tr><tr><td>DeerFlow</td><td>重协作、路由和执行环境</td></tr></tbody></table><hr><h2 id="step-5-verify-—-每个判断都要能回到源码" tabindex="-1">Step 5：Verify — 每个判断都要能回到源码 <a class="header-anchor" href="#step-5-verify-—-每个判断都要能回到源码" aria-label="Permalink to &quot;Step 5：Verify — 每个判断都要能回到源码&quot;">​</a></h2><p><strong>没有源码/测试/官方文档支撑的架构解读，只是讲故事。能回到证据的解读，才是工程论证。</strong></p><p>证据三层级（强度递减）：</p><ol><li><strong>源码</strong> — 最强证据</li><li><strong>测试</strong> — 测试比实现更清楚暴露设计边界</li><li><strong>官方文档</strong> — 确认产品语义和公开承诺</li></ol><hr><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to &quot;思考题&quot;">​</a></h2><ol><li>选一个熟悉的 Agent 框架，先写出预期它应该具备的五个地基，再去源码里验证。</li><li>拿 Claude Code / Aider / OpenHands / Hermes 任意一个，画一张不超过 10 个框的主循环图。</li><li>找一个具体组件，归到七脉，再落到双轴矩阵，说明为什么主要属于这个格子。</li></ol><hr><h2 id="关键对话总结" tabindex="-1">关键对话总结 <a class="header-anchor" href="#关键对话总结" aria-label="Permalink to &quot;关键对话总结&quot;">​</a></h2><h3 id="_1-读-agent-框架源码的三个坑" tabindex="-1">1. 读 Agent 框架源码的三个坑 <a class="header-anchor" href="#_1-读-agent-框架源码的三个坑" aria-label="Permalink to &quot;1. 读 Agent 框架源码的三个坑&quot;">​</a></h3><table tabindex="0"><thead><tr><th>坑</th><th>表现</th></tr></thead><tbody><tr><td>README 幻觉</td><td>知道&quot;能做什么&quot;，不知道&quot;为什么这样做&quot;、主循环在哪、状态怎么传</td></tr><tr><td>关键词漫游</td><td>grep 几百个文件，每个看两眼，脑子里只剩碎片</td></tr><tr><td>从入口一路钻到底</td><td>70% 代码是配置、日志、类型定义，钻进支路出不来</td></tr></tbody></table><h3 id="_2-核心原则" tabindex="-1">2. 核心原则 <a class="header-anchor" href="#_2-核心原则" aria-label="Permalink to &quot;2. 核心原则&quot;">​</a></h3><blockquote><p><strong>先知道一个 Agent Harness 理论上应该长什么样，再去源码里验证它实际什么样。</strong>——不是从零开始读，是带着双轴框架的预期去对号入座。</p></blockquote><p>任何一个工业级 Agent Harness 必然有五个地基：</p><ol><li><strong>主循环</strong> — 接收输入→装配上下文→调模型→处理工具结果→决定下一步</li><li><strong>上下文管理</strong> — 否则 token window 失控</li><li><strong>工具注册和调度</strong> — 行动空间必须有边界</li><li><strong>状态或事件记录</strong> — 长任务可恢复</li><li><strong>治理边界</strong> — 权限、沙箱、确认、日志</li></ol><h3 id="_3-filter-最具实战价值的一步" tabindex="-1">3. Filter：最具实战价值的一步 <a class="header-anchor" href="#_3-filter-最具实战价值的一步" aria-label="Permalink to &quot;3. Filter：最具实战价值的一步&quot;">​</a></h3><p><strong>判断标准：这个文件会不会改变 Agent 的决策、上下文、状态、行动或权限？</strong></p><p>第一轮不需要读的东西：</p><ul><li>CLI 参数解析、UI 布局、错误文案</li><li>telemetry 上报适配、schema 类型定义</li><li>provider SDK 包装、serialization / deserialization</li><li>测试 fixture、平台兼容性分支</li></ul><p>大部分人读源码慢，不是读得慢，是<strong>舍不得丢</strong>。</p><h3 id="_4-实战分析-aider-的三个关键设计" tabindex="-1">4. 实战分析：Aider 的三个关键设计 <a class="header-anchor" href="#_4-实战分析-aider-的三个关键设计" aria-label="Permalink to &quot;4. 实战分析：Aider 的三个关键设计&quot;">​</a></h3><p>用五步法的框架对 Aider 进行快速分析：</p><table tabindex="0"><thead><tr><th>Aider 组件</th><th>主脉</th><th>理由</th><th>辅脉</th></tr></thead><tbody><tr><td>repo map</td><td>感知（决定什么信息进入上下文）</td><td>把代码库压缩成结构化摘要，解决上下文过大问题</td><td>语义压缩（第 08 讲展开）</td></tr><tr><td>编辑 + git commit</td><td>行动 × 链式</td><td>解析 diff → 改文件 → commit，顺序执行，错误会级联</td><td></td></tr><tr><td>只读/可写文件</td><td>治理（信任预算）</td><td>限制了模型的行动空间，确保不能改不该改的文件</td><td></td></tr></tbody></table><p><strong>repo map 的辅脉值得注意</strong>：它不只是在做感知，同时在做<strong>语义压缩</strong>——把整个代码库的结构、调用链、最近修改按优先级排好，让模型&quot;瞥一眼就知道整体&quot;。一个工业级组件经常横跨多个脉，但第一遍分析时先找一个主脉就够了。</p><h3 id="_5-一句话带走" tabindex="-1">5. 一句话带走 <a class="header-anchor" href="#_5-一句话带走" aria-label="Permalink to &quot;5. 一句话带走&quot;">​</a></h3><blockquote><p><strong>逆向五步法的核心不是记住每一步叫什么，是培养读源码的纪律：先有预期 → 归到双轴坐标 → 该丢就丢（70% 代码不值得第一轮读）。每个判断都能回到源码——没有源码/测试/官方文档支撑的架构解读，只是讲故事。</strong></p></blockquote>',78)])])}const _=e(i,[["render",l]]);export{m as __pageData,_ as default};
